class Solution:
    def increasingTriplet(self, nums) -> bool:
        n = len(nums)
        for j in range(1, n - 1):
            left = any(nums[i] < nums[j] for i in range(j))
            right = any(nums[k] > nums[j] for k in range(j + 1, n))
            if left and right:
                return True
        return False

